1	/**
2	 * RFQ copy lineage via rfqItem_copied_from_id.
3	 * Copied on/by are shown only when stored on RFQItem (rfqItem_copied_on, rfqItem_copied_by).
4	 */
5	
6	const DEFAULT_MAX_DEPTH = 50;
7	
8	/**
9	 * @param {object|null} user - designflow.users row
10	 */
11	function formatUserDisplay(user) {
12	  if (!user) {
13	    return null;
14	  }
15	  const first = (user.name || '').trim();
16	  const last = (user.lastname || '').trim();
17	  const displayName =
18	    [first, last].filter(Boolean).join(' ') || user.email || 'Unknown';
19	  const initials =
20	    ((first.charAt(0) || '') + (last.charAt(0) || first.charAt(1) || '')).toUpperCase() ||
21	    '?';
22	  return {
23	    userId: user.id ?? null,
24	    displayName,
25	    initials: initials || '?',
26	    email: user.email || null,
27	  };
28	}
29	
30	/**
31	 * Build one lineage row. Copied on/by only from RFQItem columns (no audit fallback).
32	 */
33	function buildLineageEntry(item, parentItem, copiedByUser) {
34	  const isCopy = !!item.rfqItem_copied_from_id;
35	
36	  let copiedOn = null;
37	  let copiedBy = null;
38	
39	  if (isCopy && item.rfqItem_copied_on) {
40	    copiedOn = new Date(item.rfqItem_copied_on).toISOString();
41	  }
42	  if (isCopy && item.rfqItem_copied_by && copiedByUser) {
43	    copiedBy = formatUserDisplay(copiedByUser);
44	  }
45	
46	  const createdOn = item.rfqItem_created_date
47	    ? new Date(item.rfqItem_created_date).toISOString()
48	    : null;
49	  const modifiedOn = item.rfqItem_date_modified
50	    ? new Date(item.rfqItem_date_modified).toISOString()
51	    : null;
52	
53	  return {
54	    rfqItemId: item.rfqItem_id,
55	    styleNumber: item.rfqItem_style_number || null,
56	    description: item.rfqItem_description || null,
57	    rfqGroupName: item.rfqGroupName || null,
58	    copiedFromId: parentItem ? parentItem.rfqItem_id : null,
59	    copiedFromStyleNumber: parentItem ? parentItem.rfqItem_style_number || null : null,
60	    copiedOn,
61	    copiedBy,
62	    createdOn,
63	    modifiedOn,
64	    isRoot: !isCopy,
65	  };
66	}
67	
68	/**
69	 * Walk order is newest → oldest; return as-is (most recent first).
70	 */
71	function buildLineageFromWalkedItems(walkedItems) {
72	  return walkedItems.map(({ item, parentItem, copiedByUser }) =>
73	    buildLineageEntry(item, parentItem, copiedByUser)
74	  );
75	}
76	
77	/**
78	 * @param {object} models - Sequelize models bag
79	 * @param {number} rfqItemId - starting RFQ (usually the row the user right-clicked)
80	 * @param {number} [maxDepth]
81	 */
82	async function fetchRfqLineage(models, rfqItemId, maxDepth = DEFAULT_MAX_DEPTH) {
83	  const walked = [];
84	  const seen = new Set();
85	  let currentId = rfqItemId;
86	
87	  while (currentId != null && walked.length < maxDepth) {
88	    if (seen.has(currentId)) {
89	      break;
90	    }
91	    seen.add(currentId);
92	
93	    const row = await models.RFQItem.findOne({
94	      where: { rfqItem_id: currentId },
95	      include: [
96	        {
97	          model: models.RFQGroup,
98	          as: 'RFQGroup',
99	          required: false,
100	          attributes: ['RFQGroup_id', 'RFQGroup_name'],
101	        },
102	      ],
103	    });
104	
105	    if (!row) {
106	      break;
107	    }
108	
109	    const data = row.dataValues || row;
110	    const parentId = data.rfqItem_copied_from_id;
111	
112	    let parentItem = null;
113	    if (parentId) {
114	      const parentRow = await models.RFQItem.findOne({
115	        where: { rfqItem_id: parentId },
116	        attributes: ['rfqItem_id', 'rfqItem_style_number', 'rfqItem_description'],
117	      });
118	      if (parentRow) {
119	        parentItem = parentRow.dataValues || parentRow;
120	      }
121	    }
122	
123	    let copiedByUser = null;
124	    if (data.rfqItem_copied_by) {
125	      copiedByUser = await models.users.findByPk(data.rfqItem_copied_by);
126	    }
127	
128	    walked.push({
129	      item: {
130	        rfqItem_id: data.rfqItem_id,
131	        rfqItem_style_number: data.rfqItem_style_number,
132	        rfqItem_description: data.rfqItem_description,
133	        rfqItem_copied_from_id: data.rfqItem_copied_from_id,
134	        rfqItem_copied_on: data.rfqItem_copied_on,
135	        rfqItem_copied_by: data.rfqItem_copied_by,
136	        rfqItem_created_date: data.rfqItem_created_date,
137	        rfqItem_date_modified: data.rfqItem_date_modified,
138	        rfqGroupName: data.RFQGroup?.RFQGroup_name || null,
139	      },
140	      parentItem,
141	      copiedByUser: copiedByUser ? copiedByUser.dataValues || copiedByUser : null,
142	    });
143	
144	    currentId = parentId;
145	  }
146	
147	  const lineage = buildLineageFromWalkedItems(walked);
148	  const current =
149	    walked.length > 0
150	      ? {
151	          rfqItemId: walked[0].item.rfqItem_id,
152	          styleNumber: walked[0].item.rfqItem_style_number,
153	        }
154	      : null;
155	
156	  return {
157	    current,
158	    lineage,
159	    depth: lineage.length,
160	    hasCopyChain: lineage.some((e) => e.copiedFromId != null),
161	  };
162	}
163	
164	module.exports = {
165	  DEFAULT_MAX_DEPTH,
166	  formatUserDisplay,
167	  buildLineageEntry,
168	  buildLineageFromWalkedItems,
169	  fetchRfqLineage,
170	};
